import { NavLink } from 'react-router-dom';
import { PATHS } from '../../router/paths';
import './style.css';

export default function Header() {
  return (
    <header className="fixed-header">
      <nav className="site-nav">
        <NavLink to={PATHS.HOME} className="brand-logo">
          Alara React
        </NavLink>

        <ul className="nav-links">
          <li><NavLink to={PATHS.HOME} className={({ isActive }) => `nav-link${isActive ? ' active' : ''}`}>Home</NavLink></li>
          <li><NavLink to={PATHS.POSTS.ROOT} className={({ isActive }) => `nav-link${isActive ? ' active' : ''}`}>Posts</NavLink></li>
          <li><NavLink to={PATHS.PROFILE} className={({ isActive }) => `nav-link${isActive ? ' active' : ''}`}>Profile</NavLink></li>
          <li><NavLink to={PATHS.ABOUT} className={({ isActive }) => `nav-link${isActive ? ' active' : ''}`}>About</NavLink></li>
          <li><NavLink to={PATHS.TODO} className={({ isActive }) => `nav-link${isActive ? ' active' : ''}`}>Todo</NavLink></li>
          <li><NavLink to={PATHS.COUNTERS} className={({ isActive }) => `nav-link${isActive ? ' active' : ''}`}>Counters</NavLink></li>
          <li><NavLink to={PATHS.LIFECYCLE} className={({ isActive }) => `nav-link${isActive ? ' active' : ''}`}>Lifecycle</NavLink></li>
          <li><NavLink to={PATHS.HOOKS} className={({ isActive }) => `nav-link${isActive ? ' active' : ''}`}>Hooks</NavLink></li>
          <li><NavLink to={PATHS.ROUTER} className={({ isActive }) => `nav-link${isActive ? ' active' : ''}`}>Router</NavLink></li>
        </ul>
      </nav>
    </header>
  );
}
